import { generateUID } from "./utils";
/**
 * 管理所有层
 * @class
 */
class Layers {
  /**
   * 唯一标识符
   */
  uid = generateUID();

  /**
   * group element
   */
  $element;

  /**
   * 构造一个层管理器
   * @construct
   */
  constructor({ $, id }) {
    this.$element = $;
    this.$element.attr("id", id || this.uid);
  }

  /**
   * 添加新的层实例
   * @param {*} layer - Layer 示例
   */
  add(layer) {
    this.$element.node().appendChild(layer.$element.node());
  }

  /**
   * 从 id 获取层
   * @param {string} id
   */
  get(id) {
    return this.$element.select(`#${id}`);
  }
}

export default Layers;
